<?php include '../includes/db.php'; include '../includes/auth.php'; require_role('Admin'); include '../includes/header.php'; ?>

<?php if(isset($_POST['update_role'])){ $uid=(int)$_POST['user_id']; $rid=(int)$_POST['role_id']; mysqli_query($conn,"UPDATE users SET role_id=$rid WHERE user_id=$uid"); } $users=mysqli_query($conn,"SELECT u.*, r.role_name FROM users u JOIN roles r ON u.role_id=r.role_id ORDER BY u.user_id"); $roles=mysqli_query($conn,"SELECT * FROM roles"); $roleList=[]; while($r=mysqli_fetch_assoc($roles)){ $roleList[]=$r; } ?>
<section class="container py-5"><h1>Manage Users</h1><div class="table-card"><table class="table"><thead><tr><th>Name</th><th>Email</th><th>Current Role</th><th>Update Role</th></tr></thead><tbody><?php while($u=mysqli_fetch_assoc($users)): ?><tr><td><?php echo htmlspecialchars($u['full_name']); ?></td><td><?php echo htmlspecialchars($u['email']); ?></td><td><?php echo htmlspecialchars($u['role_name']); ?></td><td><form class="d-flex gap-2" method="post"><input type="hidden" name="user_id" value="<?php echo $u['user_id']; ?>"><select class="form-select" name="role_id"><?php foreach($roleList as $r): ?><option value="<?php echo $r['role_id']; ?>" <?php if($r['role_id']==$u['role_id']) echo 'selected'; ?>><?php echo htmlspecialchars($r['role_name']); ?></option><?php endforeach; ?></select><button class="btn btn-sm btn-primary" name="update_role">Save</button></form></td></tr><?php endwhile; ?></tbody></table></div></section><?php include '../includes/footer.php'; ?>
